using Apex.Application.Abstractions.Data;using Apex.Application.Abstractions.Exceptions;using Apex.Application.Abstractions.Time;using Apex.Modules.Accounting.ChartOfAccounts.Domain;using Apex.Modules.Accounting.ChartOfAccounts.Repositories;using Microsoft.AspNetCore.Mvc;
namespace Apex.Modules.Accounting.ChartOfAccounts.UseCases.ArchiveGeneralAccount;
internal sealed class ArchiveGeneralAccountHandler(IGeneralTransactionRunner tx,IGeneralAccountWriteRepository repo,IClock clock){public async Task HandleAsync(long id,CancellationToken ct)=>await tx.ExecuteAsync(async token=>{var v=await repo.GetForUpdateAsync(id,token)??throw new NotFoundException("General account was not found.",ChartOfAccountsErrors.GeneralAccountNotFound);if(await repo.HasActiveChildrenAsync(id,token))throw new BusinessRuleException("General account has active subsidiary accounts.",ChartOfAccountsErrors.HasActiveChildren);v.Archive(clock.UtcNow);await repo.UpdateAsync(v,token);},ct);}
internal static class ArchiveGeneralAccountEndpoint{internal static RouteGroupBuilder MapArchiveGeneralAccountEndpoint(this RouteGroupBuilder g){g.MapPost("/general-accounts/{id:long}/archive",async(long id,[FromServices]ArchiveGeneralAccountHandler h,CancellationToken ct)=>{await h.HandleAsync(id,ct);return Results.NoContent();}).WithName("ArchiveGeneralAccount");return g;}}
